sql:
SELECT city_name
FROM capital_cities
WHERE state_id = 0;

SELECT twitter_url
FROM social_media_links
WHERE state_id = 1;

SELECT landscape_url
FROM landscape_background_links
WHERE state_id = 0;

SELECT skyline_url
FROM skyline_background_links
WHERE state_id = 1;

SELECT seal_url
FROM seal_links
WHERE state_id = 0;

SELECT city_name, population
FROM capital_cities
ORDER BY population DESC;

SELECT state_name
FROM states
ORDER BY state_name;

